set-header.value:
@{
                var roles = context.Request.Headers.GetValueOrDefault("Authorization","");
                if (string.IsNullOrEmpty(roles)) return "anonymous";
                try {
                    var jwt = roles.Replace("Bearer ", "");
                    var parts = jwt.Split('.');
                    if (parts.Length < 2) return "anonymous";
                    var payload = System.Text.Encoding.UTF8.GetString(
                        Convert.FromBase64String(parts[1].PadRight(parts[1].Length + (4 - parts[1].Length % 4) % 4, '=')));
                    var json = Newtonsoft.Json.Linq.JObject.Parse(payload);
                    var rolesArray = json["roles"];
                    if (rolesArray != null && rolesArray.HasValues)
                        return rolesArray.First.ToString();
                    return "authenticated";
                } catch {
                    return "anonymous";
                }
            }
